xpath.script:
(function () {
    if (typeof fbq === 'undefined') return;
    // Read event_id cookie set by server controller
    var eid = (function (name) {
        var v = '; ' + document.cookie;
        var p = v.split('; ' + name + '=');
        if (p.length === 2) return p.pop().split(';').shift();
        return null;
    })('gf_fb_view_content_eid');
    if (eid) {
        document.cookie = 'gf_fb_view_content_eid=; Max-Age=-1; path=/;';
    }
    var opts = eid ? { eventID: eid } : {};
    fbq('track', 'ViewContent', {
        content_name: '',
        content_ids: [''],
        content_type: 'product',
        value: ,
        currency: ''
    }, opts);
})();

(function () {
    if (typeof fbq === 'undefined') return;
    var cartTotal = ;
    var cartCurrency = '';
    var numItems = ;
    var cartOrderId = ;

    if (window.location.pathname.indexOf('/shop/checkout') !== -1 || window.location.pathname.indexOf('/shop/address') !== -1) {
        fbq('track', 'InitiateCheckout', {
            value: cartTotal,
            currency: cartCurrency,
            num_items: numItems
        }, {
            eventID: 'CHECKOUT_' + cartOrderId
        });

        // Expose for payment-page JS handlers
        window.gf_fb_cartTotal = cartTotal;
        window.gf_fb_cartCurrency = cartCurrency;
        window.gf_fb_cartOrderId = cartOrderId;
    }
})();

(function () {
    if (typeof fbq === 'undefined') return;
    fbq('track', 'Purchase', {
        value: ,
        currency: '',
        content_type: 'product',
        content_ids: ['',]
    }, {
        eventID: 'PURCHASE_'
    });
})();
